message.content:
@startuml
skinparam UMLClassBoxStyle fillcolor: #f0f0f0
skinparam UMLActorBoxStyle fillcolor: #e6e6fa
skinparam UMLInterfaceBoxStyle fillcolor: #f0f0f0
skinparam UMLObjectBoxStyle fillcolor: #f0f0f0

actor if_http_extension {
    handle_request
}

actor zif_amp_converter {
    convert
}

object zcl_amp_scraper {
    <<if_http_extension>>
    zcl_amp_scraper
}

object zcl_amp_conv_http_json {
    <<zif_amp_converter>>
    zcl_amp_conv_http_json
}

object zcl_amp_conv_prom_keyvalue {
    <<zif_amp_converter>>
    zcl_amp_conv_prom_keyvalue
}

object zcl_amp_conv_ {
    <<zif_amp_converter>>
    zcl_amp_conv_
}

zcl_amp_scraper --> zcl_amp_conv_http_json
zcl_amp_scraper --> zcl_amp_conv_prom_keyvalue
zcl_amp_scraper --> zcl_amp_conv_

@enduml
